#!/usr/bin/env python3
"""Extract scope-relevant facts from NexaFlow markdown inventory files."""

from __future__ import annotations

import json
import re
from pathlib import Path

ROOT = Path(__file__).resolve().parents[1]
ENDPOINT_REGISTER = ROOT / "api_endpoint_register.md"
CUSTOMER_INVENTORY = ROOT / "customer_data_inventory.md"


def split_md_row(line: str) -> list[str]:
    return [cell.strip().strip("`*") for cell in line.strip().strip("|").split("|")]


def is_separator_row(line: str) -> bool:
    cells = split_md_row(line)
    return bool(cells) and all(re.fullmatch(r":?-{3,}:?", cell.strip()) for cell in cells)


def parse_endpoint_register(text: str) -> tuple[int, list[str]]:
    routes: set[str] = set()
    unauthenticated: list[str] = []

    for line in text.splitlines():
        if not line.startswith("|") or is_separator_row(line):
            continue
        cells = split_md_row(line)
        if len(cells) < 4 or cells[0].lower() == "method":
            continue
        method, route, auth = cells[0], cells[1], cells[2]
        if not route.startswith("/"):
            continue
        routes.add(route)
        if auth.lower() in {"none", "no", "n/a"}:
            unauthenticated.append(route)

    return len(routes), sorted(set(unauthenticated))


def parse_inventory(text: str) -> tuple[int | None, list[str]]:
    total_match = re.search(r"\|\s*Total active pipeline configurations\s*\|\s*\*\*([\d,]+)\*\*\s*\|", text)
    total_active_pipeline_configs = int(total_match.group(1).replace(",", "")) if total_match else None

    fields_at_risk: list[str] = []
    in_fields_table = False

    for line in text.splitlines():
        if "| Field | Type | Sensitivity | Stored in Config Object |" in line:
            in_fields_table = True
            continue
        if in_fields_table:
            if not line.startswith("|"):
                break
            if is_separator_row(line):
                continue
            cells = split_md_row(line)
            if len(cells) >= 4 and cells[3].lower() == "yes":
                fields_at_risk.append(cells[0])

    return total_active_pipeline_configs, fields_at_risk


def main() -> None:
    endpoint_text = ENDPOINT_REGISTER.read_text(encoding="utf-8")
    inventory_text = CUSTOMER_INVENTORY.read_text(encoding="utf-8")

    endpoint_route_count, routes_lacking_authentication = parse_endpoint_register(endpoint_text)
    total_active_pipeline_configs, data_fields_at_risk = parse_inventory(inventory_text)

    result = {
        "endpoint_route_count": endpoint_route_count,
        "routes_lacking_authentication": routes_lacking_authentication,
        "data_fields_at_risk": data_fields_at_risk,
        "total_active_pipeline_configs": total_active_pipeline_configs,
        "sensitivity_classification": "high",
    }
    print(json.dumps(result, indent=2))


if __name__ == "__main__":
    main()
